mapper.select:
SELECT c.id, c.article_id AS articleId, a.title AS articleTitle, c.user_id AS userId, COALESCE(u.nickname, u.username) AS userNickname, c.content, c.status, c.admin_note AS adminNote, c.created_at AS createdAt FROM comments c JOIN articles a ON a.id = c.article_id JOIN users u ON u.id = c.user_id
c.status = #{status}
ORDER BY c.created_at DESC LIMIT #{size} OFFSET #{offset}
